interface ProcessContext {
  pid: number;
  ppid: number;
  env: Record<string, string>;
  cwd: string;
  fds: { stdin: number; stdout: number; stderr: number };
  onStdout?: (data: Uint8Array) => void;
  onStderr?: (data: Uint8Array) => void;
}
```

